using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using System.Text;

namespace MyApp.Controllers;

public class ReportController : Controller
{
    private readonly ILogger<ReportController> _logger;

    public ReportController(ILogger<ReportController> logger)
    {
        _logger = logger;
    }

    // POST /Report/Export
    [HttpPost]
    public IActionResult Export()
    {
        // ASP.NET Core returns result objects — no Response.End() or ThreadAbortException.
        // The framework handles the response lifecycle; you just return a result.
        var data = GenerateReport();
        var bytes = Encoding.UTF8.GetBytes(data);

        return File(bytes, "text/csv", "report.csv");
    }

    // POST /Report/Redirect
    [HttpPost]
    public IActionResult ProcessAndRedirect()
    {
        // [Authorize] attribute is preferred over manual checks (see pitfall #3),
        // but here's the equivalent manual check:
        if (!User.Identity?.IsAuthenticated ?? true)
        {
            return RedirectToAction("Index", "Login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error processing request");
            return Redirect("/error");
        }
        // No ThreadAbortException to catch — redirects don't throw in ASP.NET Core.
    }

    private string GenerateReport() => "col1,col2\nval1,val2";
    private void ProcessRequest() { /* ... */ }
}

